# 💡解答
这里给你提供一个**Vue 2 实现**的简易计算器代码，包含双向绑定、自动计算和除数为0的异常处理，效果和题目示例一致：

```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <title>简易计算器</title>
  <script src="https://cdn.jsdelivr.net/npm/vue@2/dist/vue.js"></script>
  <style>
    .calculator {
      width: 450px;
      margin: 50px auto;
      border: 2px solid #333;
      padding: 20px;
      text-align: center;
    }
    h1 {
      font-size: 4em;
      margin: 0 0 20px;
    }
    input, select {
      font-size: 2em;
      padding: 10px;
      margin: 5px;
    }
    .result {
      font-size: 2em;
    }
  </style>
</head>
<body>
  <div id="app" class="calculator">
    <h1>简易计算器</h1>
    <input type="number" v-model="num1" placeholder="输入第一个数">
    <select v-model="operator">
      <option value="+">+</option>
      <option value="-">-</option>
      <option value="*">×</option>
      <option value="/">÷</option>
    </select>
    <input type="number" v-model="num2" placeholder="输入第二个数">
    <span class="result">{{ result }}</span>
  </div>

  <script>
    new Vue({
      el: '#app',
      data: {
        num1: 0,
        num2: 0,
        operator: '+',
        result: 0
      },
      watch: {
        // 监听操作数和运算符变化，自动重新计算
        num1() { this.calculate() },
        num2() { this.calculate() },
        operator() { this.calculate() }
      },
      methods: {
        calculate() {
          const n1 = Number(this.num1)
          const n2 = Number(this.num2)
          switch (this.operator) {
            case '+':
              this.result = n1 + n2
              break
            case '-':
              this.result = n1 - n2
              break
            case '*':
              this.result = n1 * n2
              break
            case '/':
              this.result = n2 === 0 ? '除数不能为0' : n1 / n2
              break
            default:
              this.result = ''
          }
        }
      },
      mounted() {
        // 页面加载时计算一次初始值
        this.calculate()
      }
    })
  </script>
</body>
</html>
```

